{{Japanese clan
|Name = Tōtsuōmi Kokuzō
|Crest = 
|Crest Name = 
|Main Surname = {{ill|Mononobe clan|ja|物部氏|qq=draft|qq=draft}}
|Founder = {{ill|Inagimi no Mikoto|ja|印岐美命|qq=draft|qq=draft}}
